import { describe, expect, it, vi } from 'vitest';
import * as vscode from 'vscode';
import { loadGraphViewFileInfo } from '../../../../../src/extension/graphView/files/info/loader';

describe('graphView/files/info/loader', () => {
  it('returns no payload when no workspace folder is available', async () => {
    const statFile = vi.fn();
    const ensureAnalyzerReady = vi.fn();
    const getVisitCount = vi.fn();

    const payload = await loadGraphViewFileInfo('src/main.py', {
      workspaceFolder: undefined,
      statFile,
      ensureAnalyzerReady,
      graphData: { nodes: [], edges: [] },
      getVisitCount,
    });

    expect(payload).toBeUndefined();
    expect(statFile).not.toHaveBeenCalled();
    expect(ensureAnalyzerReady).not.toHaveBeenCalled();
    expect(getVisitCount).not.toHaveBeenCalled();
  });

  it('builds file info payloads from stat, analyzer, graph, and visit state', async () => {
    const statFile = vi.fn().mockResolvedValue({ size: 456, mtime: 123 });
    const analyzer = {
      getPluginNameForFile: vi.fn(() => 'Python'),
    };
    const ensureAnalyzerReady = vi.fn().mockResolvedValue(analyzer);
    const getVisitCount = vi.fn(() => 4);

    const payload = await loadGraphViewFileInfo('src/main.py', {
      workspaceFolder: { uri: vscode.Uri.file('/test/workspace') },
      statFile,
      ensureAnalyzerReady,
      graphData: {
        nodes: [],
        edges: [
          { id: 'a', from: 'src/main.py', to: 'src/config.py' , kind: 'import', sources: [] },
          { id: 'b', from: 'src/input.py', to: 'src/main.py' , kind: 'import', sources: [] },
          { id: 'c', from: 'src/main.py', to: 'src/other.py' , kind: 'import', sources: [] },
        ],
      },
      getVisitCount,
    });

    expect(statFile).toHaveBeenCalledWith(vscode.Uri.file('/test/workspace/src/main.py'));
    expect(ensureAnalyzerReady).toHaveBeenCalledTimes(1);
    expect(analyzer.getPluginNameForFile).toHaveBeenCalledWith('src/main.py');
    expect(getVisitCount).toHaveBeenCalledWith('src/main.py');
    expect(payload).toEqual({
      path: 'src/main.py',
      size: 456,
      lastModified: 123,
      incomingCount: 1,
      outgoingCount: 2,
      plugin: 'Python',
      visits: 4,
    });
  });

  it('builds file info payloads without a plugin when the analyzer is unavailable', async () => {
    const payload = await loadGraphViewFileInfo('src/main.py', {
      workspaceFolder: { uri: vscode.Uri.file('/test/workspace') },
      statFile: vi.fn().mockResolvedValue({ size: 456, mtime: 123 }),
      ensureAnalyzerReady: vi.fn().mockResolvedValue(undefined),
      graphData: { nodes: [], edges: [] },
      getVisitCount: vi.fn(() => 4),
    });

    expect(payload).toEqual({
      path: 'src/main.py',
      size: 456,
      lastModified: 123,
      incomingCount: 0,
      outgoingCount: 0,
      plugin: undefined,
      visits: 4,
    });
  });
});

import { describe, expect, it } from 'vitest';
import { getGraphViewVisitCount, incrementGraphViewVisitCount } from '../../../../../src/extension/graphView/files/visits/counts';

describe('graphView/files/visits/counts', () => {
  it('returns zero when a file has not been visited yet', () => {
    expect(getGraphViewVisitCount({}, 'src/app.ts')).toBe(0);
  });

  it('returns the persisted visit count for a file', () => {
    expect(getGraphViewVisitCount({ 'src/app.ts': 4 }, 'src/app.ts')).toBe(4);
  });

  it('increments visit counts for new files', () => {
    expect(incrementGraphViewVisitCount({}, 'src/app.ts')).toEqual({
      visits: { 'src/app.ts': 1 },
      accessCount: 1,
    });
  });

  it('increments visit counts for previously visited files', () => {
    expect(incrementGraphViewVisitCount({ 'src/app.ts': 4 }, 'src/app.ts')).toEqual({
      visits: { 'src/app.ts': 5 },
      accessCount: 5,
    });
  });
});

